using System;\nusing System.Collections.Generic;\nusing System.Linq;\nusing System.Threading.Tasks;\nusing Microsoft.AspNetCore.Mvc;\nusing Microsoft.EntityFrameworkCore;\nusing GeneratedApp.Data;\nusing GeneratedApp.Models;\n\nnamespace GeneratedApp.Controllers\n{\n    [Route(\"api/[controller]\")]\n    [ApiController]\n    public class ExemplaireController : ControllerBase\n    {\n        private readonly AppDbContext _context;\n\n        public ExemplaireController(AppDbContext context)\n        {\n            _context = context;\n        }\n\n        // GET: api/Exemplaire\n        [HttpGet]\n        public async Task<ActionResult<IEnumerable<Exemplaire>>> GetExemplaires()\n        {\n            return await _context.Exemplaires.ToListAsync();\n        }\n\n        // GET: api/Exemplaire/{id}\n        [HttpGet(\"{id}\")]\n        public async Task<ActionResult<Exemplaire>> GetExemplaire(Guid id)\n        {\n            var exemplaire = await _context.Exemplaires.FindAsync(id);\n\n            if (exemplaire == null)\n            {\n                return NotFound();\n            }\n\n            return exemplaire;\n        }\n\n        // POST: api/Exemplaire\n        [HttpPost]\n        public async Task<ActionResult<Exemplaire>> PostExemplaire(Exemplaire exemplaire)\n        {\n            _context.Exemplaires.Add(exemplaire);\n            await _context.SaveChangesAsync();\n\n            return CreatedAtAction(nameof(GetExemplaire), new { id = exemplaire.Id }, exemplaire);\n        }\n\n        // PUT: api/Exemplaire/{id}\n        [HttpPut(\"{id}\")]\n        public async Task<IActionResult> PutExemplaire(Guid id, Exemplaire exemplaire)\n        {\n            if (id != exemplaire.Id)\n            {\n                return BadRequest();\n            }\n\n            _context.Entry(exemplaire).State = EntityState.Modified;\n\n            try\n            {\n                await _context.SaveChangesAsync();\n            }\n            catch (DbUpdateConcurrencyException)\n            {\n                if (!ExemplaireExists(id))\n                {\n                    return NotFound();\n                }\n                else\n                {\n                    throw;\n                }\n            }\n\n            return NoContent();\n        }\n\n        // DELETE: api/Exemplaire/{id}\n        [HttpDelete(\"{id}\")]\n        public async Task<IActionResult> DeleteExemplaire(Guid id)\n        {\n            var exemplaire = await _context.Exemplaires.FindAsync(id);\n            if (exemplaire == null)\n            {\n                return NotFound();\n            }\n\n            _context.Exemplaires.Remove(exemplaire);\n            await _context.SaveChangesAsync();\n\n            return NoContent();\n        }\n\n        private bool ExemplaireExists(Guid id)\n        {\n            return _context.Exemplaires.Any(e => e.Id == id);\n        }\n    }\n}